# Unit Tests for `intersection` Function

```python
import pytest


def intersection(lst1: list, lst2: list) -> list:
    set2 = set(lst2)
    seen = set()
    result = []
    for item in lst1:
        if item in set2 and item not in seen:
            result.append(item)
            seen.add(item)
    return result


class TestIntersectionHappyPath:
    """Tests for typical, expected use cases."""

    def test_basic_intersection(self):
        assert intersection([1, 2, 3, 4], [3, 4, 5, 6]) == [3, 4]

    def test_full_overlap(self):
        assert intersection([1, 2, 3], [1, 2, 3]) == [1, 2, 3]

    def test_preserves_order_of_lst1(self):
        # Order should follow lst1, not lst2
        assert intersection([4, 1, 3, 2], [1, 2, 3, 4]) == [4, 1, 3, 2]

    def test_strings(self):
        assert intersection(["a", "b", "c"], ["b", "c", "d"]) == ["b", "c"]

    def test_mixed_types(self):
        assert intersection([1, "a", 2.5], ["a", 2.5, 3]) == ["a", 2.5]

    def test_subset(self):
        assert intersection([1, 2], [1, 2, 3, 4, 5]) == [1, 2]


class TestIntersectionEdgeCases:
    """Tests for boundary and edge conditions."""

    def test_both_empty(self):
        assert intersection([], []) == []

    def test_first_empty(self):
        assert intersection([], [1, 2, 3]) == []

    def test_second_empty(self):
        assert intersection([1, 2, 3], []) == []

    def test_no_common_elements(self):
        assert intersection([1, 2, 3], [4, 5, 6]) == []

    def test_duplicates_in_lst1_deduplicated(self):
        # Duplicates in lst1 should appear only once in result
        assert intersection([1, 1, 2, 2, 3], [1, 2, 3]) == [1, 2, 3]

    def test_duplicates_in_lst2_no_effect(self):
        assert intersection([1, 2, 3], [1, 1, 2, 2, 2]) == [1, 2]

    def test_duplicates_in_both(self):
        assert intersection([1, 1, 2, 3, 3], [1, 1, 3, 3]) == [1, 3]

    def test_single_element_match(self):
        assert intersection([1], [1]) == [1]

    def test_single_element_no_match(self):
        assert intersection([1], [2]) == []

    def test_with_none_values(self):
        assert intersection([None, 1, 2], [None, 3]) == [None]

    def test_with_booleans(self):
        # In Python, True == 1 and False == 0, set behavior follows
        assert intersection([True, False], [1, 0]) == [True, False]

    def test_with_zero_and_negative(self):
        assert intersection([0, -1, -2, 3], [-1, 0, 5]) == [0, -1]

    def test_large_lists(self):
        lst1 = list(range(1000))
        lst2 = list(range(500, 1500))
        assert intersection(lst1, lst2) == list(range(500, 1000))

    def test_does_not_modify_inputs(self):
        lst1 = [1, 2, 3]
        lst2 = [2, 3, 4]
        original_lst1 = lst1.copy()
        original_lst2 = lst2.copy()
        intersection(lst1, lst2)
        assert lst1 == original_lst1
        assert lst2 == original_lst2

    def test_returns_new_list(self):
        lst1 = [1, 2, 3]
        result = intersection(lst1, [1, 2, 3])
        assert result is not lst1

    def test_tuples_as_elements(self):
        assert intersection([(1, 2), (3, 4)], [(3, 4), (5, 6)]) == [(3, 4)]


class TestIntersectionErrorCases:
    """Tests for invalid inputs and error conditions."""

    def test_unhashable_elements_in_lst2_raises(self):
        # Lists are unhashable, so set(lst2) should fail
        with pytest.raises(TypeError):
            intersection([1, 2], [[1, 2], [3, 4]])

    def test_unhashable_elements_in_lst1_raises_when_matched(self):
        # The 'in seen' check requires hashable; lists are unhashable
        with pytest.raises(TypeError):
            intersection([[1, 2], 3], [3, 4])

    def test_none_as_first_arg_raises(self):
        with pytest.raises(TypeError):
            intersection(None, [1, 2, 3])

    def test_none_as_second_arg_raises(self):
        with pytest.raises(TypeError):
            intersection([1, 2, 3], None)

    def test_non_iterable_raises(self):
        with pytest.raises(TypeError):
            intersection(123, [1, 2, 3])


@pytest.mark.parametrize("lst1,lst2,expected", [
    ([1, 2, 3], [2, 3, 4], [2, 3]),
    ([], [1, 2], []),
    ([1, 2], [], []),
    ([1, 1, 1], [1], [1]),
    (["x", "y"], ["y", "z"], ["y"]),
    ([1, 2, 3, 4, 5], [5, 4, 3, 2, 1], [1, 2, 3, 4, 5]),
])
def test_intersection_parametrized(lst1, lst2, expected):
    assert intersection(lst1, lst2) == expected
